SELECT COUNT(*) AS bookmark_count
FROM bookmark_tags
WHERE tag_id = 1;

SELECT COUNT(DISTINCT user_id) AS active_users
FROM (
    SELECT user_id FROM folders
    INTERSECT
    SELECT user_id FROM access_logs WHERE access_type = 'view'
) AS active_users_set;

SELECT folder_name
FROM folders
WHERE folder_id = (
  SELECT folder_id
  FROM folder_history
  WHERE date_time = (
    SELECT MIN(date_time)
    FROM folder_history
  )
);
